#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-20

# Eval-harness guard: dead generations must never be graded (#3036)
#
# A `claude -p` call can exit 0 and still produce nothing gradeable. Two shapes,
# both observed in CI:
#
#   1. JSON error envelope — {"is_error":true,"subtype":"error_max_turns",...}
#      with no usable .result. The old extractor did `.result // .content // .`
#      which FELL THROUGH to `.`, stringifying the whole envelope, so the grader
#      graded session metrics (duration_ms, duration_api_ms, num_turns) as if
#      they were the model's prose. Real instance: Skill Eval run 29723212799.
#   2. Effectively-blank output — empty file, whitespace-only, or an envelope
#      whose .result is "". Grades every assertion FAIL against nothing.
#
# Either shape silently flips a delta-gated verdict, in BOTH directions: a dead
# with-skill run fakes SKILL_REGRESSES, a dead baseline fakes SKILL_ADDS_VALUE.
#
# Priority: HIGH — a corrupt eval verdict is worse than no verdict.
# Reference: #3036

# strict-mode: opt-out this suite asserts NON-ZERO returns from
# classify_generation (rc=1 transient, rc=3 terminal); `set -e` would abort the
# runner on the first correct answer. `-uo pipefail` is kept.
set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
HARNESS="$PROJECT_ROOT/tests/evals/scripts/run-quality-eval.sh"

RED=$'\033[0;31m'; GREEN=$'\033[0;32m'; YELLOW=$'\033[1;33m'; NC=$'\033[0m'
PASS=0; FAIL=0
log_pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }
section() { echo; echo "${YELLOW}$1${NC}"; }

TMP=$(mktemp -d)
trap 'rm -rf "$TMP"' EXIT

echo "=========================================="
echo "  Dead-Generation Guard (#3036)"
echo "=========================================="

# Source only the two pure functions, without executing the harness body.
# They are self-contained (jq + tr + printf), so extracting them by name avoids
# the harness's arg parsing, traps and env mutation.
eval "$(awk '/^extract_output_text\(\) \{/,/^\}/' "$HARNESS")"
eval "$(awk '/^classify_generation\(\) \{/,/^\}/' "$HARNESS")"

if ! declare -F extract_output_text >/dev/null || ! declare -F classify_generation >/dev/null; then
    echo "${RED}FATAL: could not source the harness functions — were they renamed?${NC}"
    exit 1
fi

# ---------------------------------------------------------------------------
section "1. The error envelope must never reach the grader"
# ---------------------------------------------------------------------------
ENVELOPE="$TMP/max_turns.json"
cat > "$ENVELOPE" <<'JSON'
{"type":"result","subtype":"error_max_turns","is_error":true,"duration_ms":118237,"duration_api_ms":117004,"num_turns":10,"session_id":"abc"}
JSON

OUT=$(extract_output_text "$ENVELOPE")
if [[ -z "$(tr -d '[:space:]' <<< "$OUT")" ]]; then
    log_pass "extractor yields nothing gradeable for an error envelope"
else
    log_fail "extractor LEAKED the envelope: ${OUT:0:80}"
fi

LEAKED=0
for LEAK in duration_ms duration_api_ms num_turns error_max_turns; do
    if [[ "$OUT" == *"$LEAK"* ]]; then
        log_fail "session metric '$LEAK' leaked into the graded text"
        LEAKED=1
    fi
done
[[ "$LEAKED" -eq 0 ]] && log_pass "no session metrics present in extracted text"

# ---------------------------------------------------------------------------
section "2. Terminal vs transient classification"
# ---------------------------------------------------------------------------
classify_generation "$ENVELOPE" >/dev/null; RC=$?
if [[ "$RC" -eq 3 ]]; then
    log_pass "error_max_turns classified TERMINAL (rc=3) — not retried"
else
    log_fail "error_max_turns should be rc=3, got rc=$RC (a retry burns another full call)"
fi

BLANK="$TMP/blank.json"; printf '   \n\t\n' > "$BLANK"
classify_generation "$BLANK" >/dev/null; RC=$?
if [[ "$RC" -eq 1 ]]; then
    log_pass "whitespace-only classified TRANSIENT (rc=1) — retried once"
else
    log_fail "whitespace-only should be rc=1, got rc=$RC"
fi

EMPTY_RESULT="$TMP/empty_result.json"
echo '{"type":"result","subtype":"success","is_error":false,"result":"","duration_ms":900}' > "$EMPTY_RESULT"
classify_generation "$EMPTY_RESULT" >/dev/null; RC=$?
if [[ "$RC" -eq 1 ]]; then
    log_pass "success envelope with empty .result caught (a dead run wearing a live file)"
else
    log_fail "empty .result should be rc=1, got rc=$RC"
fi

# ---------------------------------------------------------------------------
section "3. Live generations still pass through untouched"
# ---------------------------------------------------------------------------
LIVE="$TMP/live.json"
echo '{"type":"result","subtype":"success","is_error":false,"result":"The doctor skill validates 15 categories and reports pass/warn/fail per category.","duration_ms":4200}' > "$LIVE"
OUT=$(extract_output_text "$LIVE")
if [[ "$OUT" == *"validates 15 categories"* ]]; then
    log_pass "live envelope yields the model's prose"
else
    log_fail "live envelope did not extract cleanly: ${OUT:0:80}"
fi
classify_generation "$LIVE" >/dev/null; RC=$?
if [[ "$RC" -eq 0 ]]; then
    log_pass "live envelope classified alive (rc=0)"
else
    log_fail "live envelope misclassified as dead (rc=$RC)"
fi

PLAIN="$TMP/plain.txt"
echo "Plain --print output with no JSON envelope at all." > "$PLAIN"
OUT=$(extract_output_text "$PLAIN")
if [[ "$OUT" == *"no JSON envelope"* ]]; then
    log_pass "plain-text (--print / --force-skill mode) passes through verbatim"
else
    log_fail "plain text was mangled: ${OUT:0:80}"
fi
classify_generation "$PLAIN" >/dev/null; RC=$?
if [[ "$RC" -eq 0 ]]; then
    log_pass "plain text classified alive"
else
    log_fail "plain text misclassified as dead (rc=$RC)"
fi

# ---------------------------------------------------------------------------
section "4. Both previously-unprotected runners now classify and retry"
# ---------------------------------------------------------------------------
for FN in run_with_skill run_baseline; do
    BODY=$(awk "/^${FN}\(\) \{/,/^\}/" "$HARNESS")
    if grep -q "classify_generation" <<< "$BODY"; then
        log_pass "$FN classifies its generation"
    else
        log_fail "$FN does not classify — a dead run would still be graded"
    fi
    if grep -q "for attempt in 1 2" <<< "$BODY"; then
        log_pass "$FN retries a transient dead generation"
    else
        log_fail "$FN has no retry loop"
    fi
done

if grep -q "_EVAL_DEAD_GENERATION" "$HARNESS"; then
    log_pass "harness propagates the dead-generation flag to the abort path"
else
    log_fail "no dead-generation flag — the abort path is missing"
fi

echo
echo "=========================================="
echo "  Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
echo "=========================================="
[ "$FAIL" -eq 0 ]
